from typing import TYPE_CHECKING, Dict, List, Optional, Tuple

from pyspark.errors import PySparkRuntimeError
from pyspark.sql.types import StructType

from pyspark.sql.streaming.state_ipc_processor import (
    StateIpcProcessor,
    TimerWriteBufferOperation,
    ValueStateWriteBufferEntry,
    MapStateWriteBufferEntry,
    TimerWriteBufferEntry,
)

if TYPE_CHECKING:
    from pyspark.sql.streaming.stateful_processor_api_client import (
        StatefulProcessorApiClient,
    )


class WriteBufferStateIpcProcessor(StateIpcProcessor):

    def __init__(self, api_client: "StatefulProcessorApiClient") -> None:
        self._api_client = api_client
        # Dict to store value state write buffer with type {state_name, ValueStateWriteBufferEntry}
        self._value_state_write_buffer: Dict[str, Optional[ValueStateWriteBufferEntry]] = {}
        # Dict to store map state write buffer with type
        # {state_name, MapStateWriteBufferEntry}
        self._map_state_write_buffer: Dict[str, Optional[MapStateWriteBufferEntry]] = {}
        # List to store timer state write buffer entries
        self._timer_write_buffer: List[TimerWriteBufferEntry] = []
        # List to store batched state requests
        self._request_batch: list = []

    @property
    def supports_ttl_state(self) -> bool:
        return False

    # --- Value state operations ---

    def value_state_exists(self, state_name: str, schema: StructType) -> Optional[bool]:
        """Handle exists() with worker cache."""
        if state_name in self._value_state_write_buffer:
            if self._value_state_write_buffer[state_name] is not None:
                return True
            else:
                return False
        return None  # Continue with original logic

    def value_state_get(
        self, state_name: str, schema: StructType
    ) -> Optional[Tuple[Optional[Tuple], bool]]:
        """Handle get() with worker cache.
        Returns (value, found_in_cache) tuple or None to continue with original logic.
        """
        if state_name in self._value_state_write_buffer:
            if self._value_state_write_buffer[state_name] is None:
                # If the value state is cached as None, it means the state was cleared previously.
                return (None, True)
            else:
                # If the value state is cached, return it directly.
                value_state_entry = self._value_state_write_buffer[
                    state_name
                ]
                return (value_state_entry.value, True)
        return None  # Continue with original logic

    def value_state_update(self, state_name: str, value: Tuple, schema: StructType) -> None:
        """Handle update() with worker cache."""
        self._value_state_write_buffer[
            state_name
        ] = ValueStateWriteBufferEntry(value=value, schema=schema)

    def value_state_clear(self, state_name: str) -> None:
        """Handle clear() with worker cache."""
        # Set the value of ValueState to None to represent clear() call.
        self._value_state_write_buffer[state_name] = None

    # --- Map state operations ---

    def map_state_exists(self, state_name: str) -> Optional[bool]:
        """Handle exists() with worker cache"""
        if state_name in self._map_state_write_buffer:
            if self._map_state_write_buffer[state_name] is None:
                # If the map state is cached as None, it means the state was cleared previously.
                return False
            else:
                return True
        return None  # Continue with original logic

    def map_state_get_value(
        self, state_name: str, user_key: Tuple,
        user_key_schema: StructType, value_schema: StructType,
    ) -> Optional[Tuple[Optional[Tuple], bool]]:
        """Handle get_value() with worker cache.
        Returns (value, found_in_cache) tuple or None to continue with original logic.
        """
        if state_name in self._map_state_write_buffer:
            if self._map_state_write_buffer[state_name] is None:
                return (None, True)
            else:
                map_buffer_entry = self._map_state_write_buffer[
                    state_name
                ]
                user_key_value_pairs = map_buffer_entry.user_key_value_pairs
                if user_key in user_key_value_pairs:
                    # If the user_key in the state_name map state is cached, return it directly.
                    return (user_key_value_pairs[user_key], True)
        return None  # Continue with original logic

    def map_state_contains_key(
        self, state_name: str, user_key: Tuple,
        user_key_schema: StructType,
    ) -> Optional[bool]:
        """Handle contains_key() with worker cache."""
        if state_name in self._map_state_write_buffer:
            if self._map_state_write_buffer[state_name] is None:
                # If the map state is cached as None, it means the state was cleared previously.
                return False
            else:
                map_buffer_entry = self._map_state_write_buffer[
                    state_name
                ]
                user_key_value_pairs = map_buffer_entry.user_key_value_pairs
                if user_key in user_key_value_pairs:
                    if user_key_value_pairs[user_key] is not None:
                        return True
                    else:
                        # If the user_key is cached with None value,
                        # it means it was removed previously.
                        return False
        return None  # Continue with original logic

    def map_state_update_value(
        self, state_name: str, user_key: Tuple, value: Tuple,
        user_key_schema: StructType, value_schema: StructType,
    ) -> None:
        """Handle update_value() with worker cache."""
        if (
            state_name in self._map_state_write_buffer and
            self._map_state_write_buffer[state_name] is None
        ):
            # If the write buffer contains a clear(), we need to flush it first.
            self._build_and_flush_request_batch()
        if value is None:
            raise PySparkRuntimeError(
                f"None is not a valid value to put into map state '{state_name}' with"
                f" user_key {user_key}."
            )
        if state_name not in self._map_state_write_buffer:
            map_state_entry = MapStateWriteBufferEntry(
                user_key_value_pairs={user_key: value},
                user_key_schema=user_key_schema,
                value_schema=value_schema
            )
            self._map_state_write_buffer[
                state_name
            ] = map_state_entry
        else:
            map_state_entry = self._map_state_write_buffer[
                state_name
            ]
            map_state_entry.user_key_value_pairs[user_key] = value

    def map_state_remove_key(
        self, state_name: str, key: Tuple,
        user_key_schema: StructType, value_schema: StructType,
    ) -> None:
        """Handle remove_key() with worker cache."""
        if (
            state_name in self._map_state_write_buffer and
            self._map_state_write_buffer[state_name] is None
        ):
            # If the write buffer contains a clear(), we can treat remove_key() as no-op.
            return
        if state_name in self._map_state_write_buffer:
            map_buffer_entry = self._map_state_write_buffer[
                state_name
            ]
            user_key_value_pairs = map_buffer_entry.user_key_value_pairs
            user_key_value_pairs[key] = None
        else:
            # Set the user key of MapState to None to represent remove_key() call.
            map_state_entry = MapStateWriteBufferEntry(
                user_key_value_pairs={key: None},
                user_key_schema=user_key_schema,
                value_schema=value_schema
            )
            self._map_state_write_buffer[
                state_name
            ] = map_state_entry

    def map_state_clear(self, state_name: str) -> None:
        """Handle clear() with worker cache."""
        # Set to None to indicate a clear(), regardless of whether we had pending writes.
        # This ensures clear() on a map state that was only ever read (never written to the
        # buffer) is properly recorded, rather than being silently swallowed.
        self._map_state_write_buffer[state_name] = None

    # --- Timer operations ---

    def buffer_timer(
        self, expiry_timestamp_ms: int, operation: TimerWriteBufferOperation
    ) -> None:
        self._timer_write_buffer.append(
            TimerWriteBufferEntry(
                expiryTimestampMs=expiry_timestamp_ms, operation=operation
            )
        )

    # --- Lifecycle hooks ---

    def on_new_grouping_key(self, key: Tuple) -> None:
        import pyspark.sql.streaming.proto.StateMessage_pb2 as stateMessage
        self._build_request_batch_from_write_buffer()
        key_bytes = self._api_client._serialize_to_bytes(self._api_client.key_schema, key)
        set_implicit_key = stateMessage.SetImplicitKey(key=key_bytes)
        request = stateMessage.ImplicitGroupingKeyRequest(setImplicitKey=set_implicit_key)
        message = stateMessage.StateUnitRequest(implicitGroupingKeyRequest=request)
        self._request_batch.append(message)
        self._flush_request_batch()

    def on_partition_close(self) -> None:
        import pyspark.sql.streaming.proto.StateMessage_pb2 as stateMessage
        self._build_request_batch_from_write_buffer()
        remove_implicit_key = stateMessage.RemoveImplicitKey()
        request = stateMessage.ImplicitGroupingKeyRequest(removeImplicitKey=remove_implicit_key)
        message = stateMessage.StateUnitRequest(implicitGroupingKeyRequest=request)
        self._request_batch.append(message)
        self._flush_request_batch()

    def on_timers_complete(self) -> None:
        self._build_and_flush_request_batch()

    def on_iterator_start(self) -> None:
        self._build_and_flush_request_batch()

    # --- Private: batch-building and flushing ---

    def _build_request_batch_from_write_buffer(self) -> None:
        import pyspark.sql.streaming.proto.StateMessage_pb2 as stateMessage
        if self._value_state_write_buffer:
            for state_name, value_state_entry in self._value_state_write_buffer.items():
                if value_state_entry is None:
                    clear_call = stateMessage.Clear()
                    value_state_call = stateMessage.ValueStateCall(
                        stateName=state_name, clear=clear_call
                    )
                else:
                    bytes = self._api_client._serialize_to_bytes(
                        value_state_entry.schema,
                        value_state_entry.value
                    )
                    update_call = stateMessage.ValueStateUpdate(value=bytes)
                    value_state_call = stateMessage.ValueStateCall(
                        stateName=state_name, valueStateUpdate=update_call
                    )
                state_variable_request = stateMessage.StateVariableRequest(
                    valueStateCall=value_state_call
                )
                message = stateMessage.StateUnitRequest(
                    stateVariableRequest=state_variable_request
                )
                self._request_batch.append(message)
            self._value_state_write_buffer.clear()
        if self._map_state_write_buffer:
            for state_name, map_state_entry in self._map_state_write_buffer.items():
                if map_state_entry is None:
                    clear_call = stateMessage.Clear()
                    map_state_call = stateMessage.MapStateCall(
                        stateName=state_name, clear=clear_call
                    )
                    state_variable_request = stateMessage.StateVariableRequest(
                        mapStateCall=map_state_call
                    )
                    message = stateMessage.StateUnitRequest(
                        stateVariableRequest=state_variable_request
                    )
                    self._request_batch.append(message)
                else:
                    user_key_value_pairs = map_state_entry.user_key_value_pairs
                    user_key_schema = map_state_entry.user_key_schema
                    value_schema = map_state_entry.value_schema
                    for user_key, value in user_key_value_pairs.items():
                        if value is None:
                            key_bytes = self._api_client._serialize_to_bytes(user_key_schema, user_key)
                            remove_key_call = stateMessage.RemoveKey(userKey=key_bytes)
                            map_state_call = stateMessage.MapStateCall(
                                stateName=state_name, removeKey=remove_key_call
                            )
                        else:
                            key_bytes = self._api_client._serialize_to_bytes(user_key_schema, user_key)
                            value_bytes = self._api_client._serialize_to_bytes(value_schema, value)
                            update_value_call = stateMessage.UpdateValue(
                                userKey=key_bytes, value=value_bytes
                            )
                            map_state_call = stateMessage.MapStateCall(
                                stateName=state_name, updateValue=update_value_call
                            )
                        state_variable_request = stateMessage.StateVariableRequest(
                            mapStateCall=map_state_call
                        )
                        message = stateMessage.StateUnitRequest(
                            stateVariableRequest=state_variable_request
                        )
                        self._request_batch.append(message)
            self._map_state_write_buffer.clear()
        if self._timer_write_buffer:
            for timer_entry in self._timer_write_buffer:
                expiry_time_stamp_ms = timer_entry.expiryTimestampMs
                operation = timer_entry.operation
                if operation == TimerWriteBufferOperation.REGISTER:
                    register_call = stateMessage.RegisterTimer(
                        expiryTimestampMs=expiry_time_stamp_ms
                    )
                    state_call_command = stateMessage.TimerStateCallCommand(register=register_call)
                    call = stateMessage.StatefulProcessorCall(timerStateCall=state_call_command)
                    message = stateMessage.StateUnitRequest(statefulProcessorCall=call)
                    self._request_batch.append(message)
                elif operation == TimerWriteBufferOperation.DELETE:
                    delete_call = stateMessage.DeleteTimer(expiryTimestampMs=expiry_time_stamp_ms)
                    state_call_command = stateMessage.TimerStateCallCommand(delete=delete_call)
                    call = stateMessage.StatefulProcessorCall(timerStateCall=state_call_command)
                    message = stateMessage.StateUnitRequest(statefulProcessorCall=call)
                    self._request_batch.append(message)
            self._timer_write_buffer.clear()

    def _flush_request_batch(self) -> None:
        import pyspark.sql.streaming.proto.StateMessage_pb2 as stateMessage
        if not self._request_batch:
            return
        batch_call = stateMessage.BatchRequest(
            stateUnitRequests=self._request_batch
        )
        message = stateMessage.StateRequest(batchRequest=batch_call)
        self._api_client._send_proto_message(message.SerializeToString())
        response_message = self._api_client._receive_proto_message()
        status = response_message[0]
        if status != 0:
            # TODO(SPARK-49233): Classify user facing errors.
            raise PySparkRuntimeError(
                f"Error processing state request: " f"{response_message[1]}"
            )
        self._request_batch = []

    def _build_and_flush_request_batch(self) -> None:
        self._build_request_batch_from_write_buffer()
        self._flush_request_batch()
